"use client";

import { use, useMemo, useState } from "react";
import { useRouter } from "next/navigation";
import { ArrowLeft, Banknote, Building2, FileText, Mail, MapPin, Phone, Star } from "lucide-react";
import { useAuth } from "@/app/(auth)/context/AuthContext";
import { EmptyState, MiniMetric, ProgressRow, SectionCard, neo } from "@/app/(dashboard)/manager/dashboard/DashboardWidgets";
import useVendorData from "../hooks/useVendorData";
import VendorPaymentDialog from "../components/VendorPaymentDialog";

const money=(value)=>`₹${Number(value||0).toLocaleString("en-IN",{maximumFractionDigits:0})}`;const date=(value)=>value?new Date(value?.toDate?.()||value).toLocaleDateString("en-IN",{day:"2-digit",month:"short",year:"numeric"}):"—";
export default function VendorProfilePage({params}){const {id}=use(params);const {company}=useAuth();const router=useRouter();const data=useVendorData(company?.id);const [tab,setTab]=useState("overview");const [payment,setPayment]=useState(false);const vendor=useMemo(()=>data.analytics.vendors.find((item)=>item.id===id),[data.analytics.vendors,id]);
 if(data.loading)return <div className="space-y-4 p-5">{Array.from({length:5},(_,i)=><div key={i} className="h-28 animate-pulse rounded-3xl bg-white/70"/>)}</div>;if(!vendor)return <div className="p-10">Vendor not found.</div>;
 const tabs=["overview","projects","payments","documents","activity"];let running=vendor.allocated;const paymentRows=vendor.payments.map((item)=>({...item,runningBalance:item.runningBalance??Math.max(0,(running-=Number(item.amount||0)))}));
 return <div className="space-y-6 px-2 py-2 sm:px-6"><button onClick={()=>router.back()} className="flex items-center gap-2 text-sm font-bold text-blue-600"><ArrowLeft size={17}/>Back to vendors</button><header className={`${neo} rounded-3xl bg-white p-6`}><div className="flex flex-col gap-5 lg:flex-row lg:items-center lg:justify-between"><div className="flex items-center gap-4"><span className="grid h-14 w-14 place-items-center rounded-2xl bg-blue-600 text-white"><Building2/></span><div><h1 className="text-2xl font-bold text-slate-800">{vendor.companyName}</h1><p className="text-sm text-slate-500">{vendor.vendorId} • {vendor.category||"General"} • <span className="capitalize">{vendor.status}</span></p></div></div><button onClick={()=>setPayment(true)} className="flex items-center gap-2 rounded-xl bg-blue-600 px-4 py-2.5 text-sm font-bold text-white"><Banknote size={17}/>Create payment</button></div><div className="mt-6 grid gap-3 sm:grid-cols-2 lg:grid-cols-4"><Info icon={Phone} label="Phone" value={vendor.phone}/><Info icon={Mail} label="Email" value={vendor.email}/><Info icon={MapPin} label="Location" value={[vendor.address?.city,vendor.address?.state].filter(Boolean).join(", ")}/><Info icon={Star} label="Rating" value={`${vendor.rating||0}/5`}/></div></header><section className="grid grid-cols-2 gap-3 md:grid-cols-4"><MiniMetric label="Total work given" value={vendor.allocated} format="currency"/><MiniMetric label="Amount paid" value={vendor.paid} format="currency"/><MiniMetric label="Outstanding" value={vendor.outstanding} format="currency" tone="text-red-600"/><MiniMetric label="Performance" value={vendor.performance} format="percent"/></section><nav className={`${neo} flex gap-2 overflow-x-auto rounded-2xl p-2`}>{tabs.map((item)=><button key={item} onClick={()=>setTab(item)} className={`rounded-xl px-4 py-2.5 text-sm font-bold capitalize ${tab===item?"bg-blue-600 text-white":"text-slate-600"}`}>{item}</button>)}</nav>{tab==="overview"&&<div className="grid gap-6 lg:grid-cols-2"><SectionCard title="Business details"><div className="grid grid-cols-2 gap-3"><Detail label="Contact person" value={vendor.contactPerson}/><Detail label="GST" value={vendor.gstNo}/><Detail label="PAN" value={vendor.panNo}/><Detail label="UPI" value={vendor.upi}/><Detail label="Services" value={(vendor.services||[]).join(", ")}/><Detail label="Address" value={[vendor.address?.line1,vendor.address?.city,vendor.address?.state,vendor.address?.postalCode].filter(Boolean).join(", ")}/></div></SectionCard><SectionCard title="Payment tracker"><ProgressRow label="Paid against allocation" value={vendor.paymentPercent} detail={`${vendor.paymentPercent.toFixed(0)}%`}/><div className="mt-5 grid grid-cols-2 gap-3"><MiniMetric label="Pending" value={vendor.pendingPayments} format="currency"/><MiniMetric label="Completed" value={vendor.completedPayments} format="currency"/></div></SectionCard><SectionCard title="Bank details"><div className="grid grid-cols-2 gap-3"><Detail label="Account name" value={vendor.bankDetails?.accountName}/><Detail label="Account number" value={vendor.bankDetails?.accountNumber}/><Detail label="Bank" value={vendor.bankDetails?.bankName}/><Detail label="IFSC" value={vendor.bankDetails?.ifsc}/></div></SectionCard><SectionCard title="Performance"><ProgressRow label="Vendor performance" value={vendor.performance} detail={`${vendor.performance.toFixed(0)}%`} color="bg-violet-500"/><p className="mt-4 text-sm text-slate-500">Based on rating and completed assigned work.</p></SectionCard></div>}{tab==="projects"&&<SectionCard title="Projects assigned">{vendor.assignments.length?<div className="space-y-3">{vendor.assignments.map((item)=><button key={item.projectId} onClick={()=>router.push(`/manager/projects/${item.projectId}`)} className="w-full rounded-2xl border bg-white p-4 text-left"><div className="flex justify-between"><strong>{item.projectName}</strong><span>{Number(item.progress||0)}%</span></div><div className="mt-3 grid grid-cols-3 text-xs text-slate-500"><span>Allocated {money(item.allocatedAmount)}</span><span>Paid {money(item.paidAmount)}</span><span>Target {date(item.targetCompletion)}</span></div></button>)}</div>:<EmptyState label="No assigned projects"/>}</SectionCard>}{tab==="payments"&&<SectionCard title="Payment history" subtitle="Running balance after every vendor payment">{paymentRows.length?<div className="overflow-x-auto"><table className="w-full min-w-[850px] text-sm"><thead><tr className="border-b text-left text-xs uppercase text-slate-400"><th className="p-3">Date</th><th>Amount</th><th>Project</th><th>Reference</th><th>Status</th><th>Approved by</th><th>Remarks</th><th>Balance</th></tr></thead><tbody>{paymentRows.map((item)=><tr key={item.id} className="border-b"><td className="p-3">{date(item.date||item.createdAt)}</td><td className="font-bold">{money(item.amount)}</td><td>{item.projectName}</td><td>{item.referenceNumber||"—"}</td><td className="capitalize">{item.status}</td><td>{item.approvedBy?.name||"—"}</td><td>{item.remarks||"—"}</td><td>{money(item.runningBalance)}</td></tr>)}</tbody></table></div>:<EmptyState label="No vendor payments"/>}</SectionCard>}{tab==="documents"&&<SectionCard title="Vendor documents">{vendor.documents?.length?<div className="space-y-2">{vendor.documents.map((item,index)=><div key={item.id||index} className="flex gap-3 rounded-2xl border bg-white p-4"><FileText/><span>{item.name||item.fileName}</span></div>)}</div>:<EmptyState label="No vendor documents"/>}</SectionCard>}{tab==="activity"&&<SectionCard title="Activity timeline">{vendor.payments.length?<div className="space-y-3">{vendor.payments.map((item)=><div key={item.id} className="flex gap-3 rounded-2xl border bg-white p-4"><span className="mt-1 h-3 w-3 rounded-full bg-blue-500"/><div><strong>Vendor payment • {money(item.amount)}</strong><p className="text-sm text-slate-500">{item.projectName} • {date(item.date||item.createdAt)} • {item.referenceNumber||"No reference"}</p></div></div>)}</div>:<EmptyState label="No vendor activity"/>}</SectionCard>}<VendorPaymentDialog open={payment} onClose={()=>setPayment(false)} companyId={company.id} vendors={data.vendors} projects={data.projects} initialVendor={vendor}/></div>}
function Info({icon:Icon,label,value}){return <div className="flex gap-3 rounded-2xl bg-[#F9FAFC] p-3"><Icon size={17} className="text-blue-600"/><span><small className="block text-slate-400">{label}</small><strong className="text-sm">{value||"—"}</strong></span></div>}function Detail({label,value}){return <div className="rounded-2xl border bg-white p-3"><p className="text-xs text-slate-400">{label}</p><p className="mt-1 break-words text-sm font-bold">{value||"—"}</p></div>}
